"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[83894],{68967:e=>{e.exports=JSON.parse('{"tag":{"label":"animal","permalink":"/dst-api-webdocs/docs/tags/animal","allTagsPath":"/dst-api-webdocs/docs/tags","count":13,"items":[{"id":"game-scripts/prefabs/babybeefalo","title":"Babybeefalo","description":"A growth-stage-based animal prefab that matures through defined life phases, interacts with beefalo herds, and supports combat, foraging, and periodic waste production.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/babybeefalo"},{"id":"game-scripts/prefabs/catcoon","title":"Catcoon","description":"Implements the catcoon creature, a tameable animal that interacts with players through trading, retching gifts, and combat with flocking behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/catcoon"},{"id":"game-scripts/brains/deerbrain","title":"Deerbrain","description":"Manages the behavior tree for deer entities, coordinating solo and herd-based AI including fleeing, wandering, grazing, and alert responses.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/deerbrain"},{"id":"game-scripts/prefabs/grassgekko","title":"Grassgekko","description":"Defines the Grassgekko entity, a small animal prefab that patrols, sleeps in short naps, and joins herds.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/grassgekko"},{"id":"game-scripts/prefabs/lightcrab","title":"Lightcrab","description":"A small, glowing amphibious creature that emits light and drops loot upon death.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightcrab"},{"id":"game-scripts/prefabs/lightninggoat","title":"Lightninggoat","description":"Implements the lightning goat entity with charging behavior, passive electric retaliation, and herd-based AI.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lightninggoat"},{"id":"game-scripts/brains/otterbrain","title":"Otterbrain","description":"AI behavior controller for the Otter character, managing foraging, looting, fishing, and home-stashing behaviors via a priority-based behavior tree.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/otterbrain"},{"id":"game-scripts/prefabs/penguin","title":"Penguin","description":"An animal entity with combat, herding, and team-based behavior that spawns from the Penguin Spawner and interacts with hunger, inventory, and moon mutation systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/penguin"},{"id":"game-scripts/brains/penguinbrain","title":"Penguinbrain","description":"AI brain governing penguin behavior including egg laying, retrieval, foraging, fleeing from predators, and group migration.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/penguinbrain"},{"id":"game-scripts/prefabs/polly_rogers","title":"Polly Rogers","description":"Provides the definition and shared logic for two companion creatures: a flying bird (Polly Rogers) and a salt-shedding amphibious dog (Salty Dog), each with distinct behaviors, appearances, and interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/polly_rogers"},{"id":"game-scripts/prefabs/quagmire_pebblecrab","title":"Quagmire Pebblecrab","description":"A small, non-hostile crab prefab found in the Quagmire region that serves as a collectible animal with basic creature physics and animation states.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_pebblecrab"},{"id":"game-scripts/prefabs/tallbird","title":"Tallbird","description":"Manages the behavior, combat, and nesting logic for the Tallbird character entity in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tallbird"},{"id":"game-scripts/prefabs/ticoon","title":"Ticoon","description":"A companion entity that tracks and retrieves hidden Kitcoons for a player leader, with combat and quest management capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ticoon"}],"unlisted":false}}')}}]);